import { Link } from 'react-router-dom';

const DUMMY_EVENTS = [
    {
        eventId: 'e1',
        title: 'Event 1'
    },
    {
        eventId: 'e1',
        title: 'Event 2'
    }
]

function EventsPage() {
    return <>
        <h1>Events Page</h1>

        <ul>
            {DUMMY_EVENTS.map((eventy) => (
                <li key={eventy.id}>
                    <Link to={`/events/${eventy.eventId}`}>{eventy.title}</Link>
                </li>
            ))}
        </ul>
    </>
}

export default EventsPage;
